import React, { useEffect } from 'react';
import FormControl from '@material-ui/core/FormControl';
import InputLabel from '@material-ui/core/InputLabel';
import Select from '@material-ui/core/Select';
import MenuItem from '@material-ui/core/MenuItem';
import { makeStyles } from '@material-ui/core/styles'; // Importera makeStyles

// Skapa en makeStyles-funktion för att definiera anpassade stilar
const useStyles = makeStyles((theme) => ({
  selectedMenuItem: {
    backgroundColor: theme.palette.primary.main, // Använd primärfärgen eller en annan färg efter behov
    color: theme.palette.primary.contrastText, // Anpassa textfärgen för att vara synlig på bakgrundsfärgen
  },
}));

function CategorySelect({
  selectedCategory,
  showExistingCategories,
  handleSelectChange,
  menuData,
  selectedSubCategoryValues,
  handleSubCategoryChange,
  existingCategories,
}) {
  const classes = useStyles(); // Använd makeStyles för att hämta stilar

  useEffect(() => {
    console.log("exist: ", existingCategories)
  }, [])

  return (
    <div>
      <FormControl variant="outlined">
        <InputLabel id="category">Category</InputLabel>
        <Select
          labelId="category"
          id="category"
          value={selectedCategory}
          onChange={handleSelectChange}
          label="Category"
        >
          {existingCategories.map((category, index) => (
            <MenuItem key={index} value={category.main} className={selectedCategory === category.main ? classes.selectedMenuItem : null}>
              {category.main}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
      {selectedCategory && (
        <FormControl variant="outlined">
          <InputLabel id="subCategory">Sub Category</InputLabel>
          <Select
            labelId="subCategory"
            id="subCategory"
            multiple
            value={selectedSubCategoryValues}
            onChange={handleSubCategoryChange}
            label="Sub Category"
          >
            {existingCategories.find(category => category.main === selectedCategory)?.sub.map(
              (subCategory, index) => (
                <MenuItem key={index} value={subCategory} className={selectedSubCategoryValues.includes(subCategory) ? classes.selectedMenuItem : null}>
                  {subCategory}
                </MenuItem>
              )
            )}
          </Select>
        </FormControl>
      )}
    </div>
  );
}

export default CategorySelect;
